In a well-structured application architecture, the services layer should interact with the repository layer rather than directly with the database session. This approach offers several advantages:

1. **Separation of Concerns**: The repository layer handles database-specific operations, while the services layer focuses on business logic.
2. **Testability**: By decoupling the services layer from the database, you can easily mock the repository layer during unit testing.
3. **Flexibility**: If you need to change the database or ORM technology, you only need to modify the repository layer, not the entire application.

### Example Architecture

#### Repository Layer

The repository layer interacts with the database and provides a clean interface for the services layer to use.

```python
from sqlalchemy.orm import Session
from .models import User

class UserRepository:
    def __init__(self, db: Session):
        self.db = db

    def get_user(self, user_id: int) -> User:
        return self.db.query(User).filter(User.id == user_id).first()

    def get_users(self, skip: int = 0, limit: int = 100) -> list[User]:
        return self.db.query(User).offset(skip).limit(limit).all()

    def create_user(self, user: User) -> User:
        self.db.add(user)
        self.db.commit()
        self.db.refresh(user)
        return user

    def update_user(self, user: User) -> User:
        self.db.commit()
        self.db.refresh(user)
        return user

    def delete_user(self, user: User) -> None:
        self.db.delete(user)
        self.db.commit()
```

#### Services Layer

The services layer contains the business logic and interacts with the repository layer.

```python
from sqlalchemy.orm import Session
from .repositories import UserRepository

class UserService:
    def __init__(self, db: Session):
        self.user_repo = UserRepository(db)

    def get_user(self, user_id: int) -> User:
        return self.user_repo.get_user(user_id)

    def get_users(self, skip: int = 0, limit: int = 100) -> list[User]:
        return self.user_repo.get_users(skip, limit)

    def create_user(self, user: User) -> User:
        return self.user_repo.create_user(user)

    def update_user(self, user: User) -> User:
        return self.user_repo.update_user(user)

    def delete_user(self, user: User) -> None:
        self.user_repo.delete_user(user)
```

#### FastAPI Integration

Finally, you can integrate the services layer with FastAPI to handle HTTP requests.

```python
from fastapi import APIRouter, Depends
from sqlalchemy.orm import Session
from .database import get_db
from .services import UserService
from .schemas import UserCreate, UserUpdate

router = APIRouter()

@router.post("/users/", response_model=UserCreate)
def create_user(user: UserCreate, db: Session = Depends(get_db)):
    service = UserService(db)
    db_user = User(email=user.email, hashed_password=get_password_hash(user.password))
    return service.create_user(db_user)

@router.get("/users/{user_id}", response_model=UserCreate)
def get_user(user_id: int, db: Session = Depends(get_db)):
    service = UserService(db)
    return service.get_user(user_id)

@router.get("/users/", response_model=list[UserCreate])
def get_users(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    service = UserService(db)
    return service.get_users(skip, limit)

@router.put("/users/{user_id}", response_model=UserUpdate)
def update_user(user_id: int, user: UserUpdate, db: Session = Depends(get_db)):
    service = UserService(db)
    db_user = service.get_user(user_id)
    db_user.email = user.email
    db_user.hashed_password = get_password_hash(user.password)
    return service.update_user(db_user)

@router.delete("/users/{user_id}")
def delete_user(user_id: int, db: Session = Depends(get_db)):
    service = UserService(db)
    db_user = service.get_user(user_id)
    service.delete_user(db_user)
    return {"detail": "User deleted"}
```

### Summary

By following this architecture, you ensure that your application is modular, testable, and maintainable. The services layer is focused on business logic, while the repository layer handles database interactions, making it easier to manage and test each component independently.

This approach is highly recommended for building robust and scalable applications.

